/* ─── HOOKS ─────────────────────────────────────────────────────────── */
function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, inView];
}

function useTypingEffect(words, speed = 100, pause = 1800) {
  const [display, setDisplay] = useState("");
  const [wordIdx, setWordIdx] = useState(0);
  const [charIdx, setCharIdx] = useState(0);
  const [deleting, setDeleting] = useState(false);
  useEffect(() => {
    const current = words[wordIdx];
    const timeout = setTimeout(() => {
      if (!deleting) {
        setDisplay(current.slice(0, charIdx + 1));
        if (charIdx + 1 === current.length) setTimeout(() => setDeleting(true), pause);
        else setCharIdx(c => c + 1);
      } else {
        setDisplay(current.slice(0, charIdx - 1));
        if (charIdx - 1 === 0) { setDeleting(false); setWordIdx(w => (w + 1) % words.length); setCharIdx(0); }
        else setCharIdx(c => c - 1);
      }
    }, deleting ? speed / 2 : speed);
    return () => clearTimeout(timeout);
  }, [charIdx, deleting, wordIdx, words, speed, pause]);
  return display;
}

/* ─── PARTICLE CANVAS ───────────────────────────────────────────────── */
function ParticleCanvas() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let W = canvas.width = window.innerWidth;
    let H = canvas.height = window.innerHeight;
    const particles = Array.from({ length: 80 }, () => ({
      x: Math.random() * W, y: Math.random() * H,
      vx: (Math.random() - 0.5) * 0.4, vy: (Math.random() - 0.5) * 0.4,
      r: Math.random() * 1.5 + 0.5,
      alpha: Math.random() * 0.5 + 0.1,
    }));
    let mouse = { x: W / 2, y: H / 2 };
    const onMove = e => { mouse.x = e.clientX; mouse.y = e.clientY; };
    window.addEventListener("mousemove", onMove);
    const onResize = () => { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; };
    window.addEventListener("resize", onResize);
    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      particles.forEach(p => {
        const dx = mouse.x - p.x, dy = mouse.y - p.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 120) { p.vx += dx * 0.00015; p.vy += dy * 0.00015; }
        p.x += p.vx; p.y += p.vy;
        p.vx *= 0.99; p.vy *= 0.99;
        if (p.x < 0 || p.x > W) p.vx *= -1;
        if (p.y < 0 || p.y > H) p.vy *= -1;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(0,229,255,${p.alpha})`;
        ctx.fill();
      });
      particles.forEach((a, i) => particles.slice(i + 1).forEach(b => {
        const d = Math.hypot(a.x - b.x, a.y - b.y);
        if (d < 100) {
          ctx.beginPath();
          ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = `rgba(0,229,255,${0.12 * (1 - d / 100)})`;
          ctx.lineWidth = 0.5; ctx.stroke();
        }
      }));
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(raf); window.removeEventListener("mousemove", onMove); window.removeEventListener("resize", onResize); };
  }, []);
  return <canvas ref={canvasRef} style={{ position: "fixed", top: 0, left: 0, zIndex: 0, pointerEvents: "none" }} />;
}

/* ─── COUNTER ANIMATION ─────────────────────────────────────────────── */
function AnimatedCounter({ target, suffix = "" }) {
  const [count, setCount] = useState(0);
  const [ref, inView] = useInView(0.5);
  useEffect(() => {
    if (!inView) return;
    const num = parseInt(target);
    let start = 0;
    const step = Math.ceil(num / 40);
    const timer = setInterval(() => {
      start += step;
      if (start >= num) { setCount(num); clearInterval(timer); }
      else setCount(start);
    }, 40);
    return () => clearInterval(timer);
  }, [inView, target]);
  return <span ref={ref}>{count}{suffix}</span>;
}

/* ─── SKILL BAR ─────────────────────────────────────────────────────── */
function SkillBar({ name, level, color, delay = 0 }) {
  const [ref, inView] = useInView(0.3);
  return (
    <div ref={ref} style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6, fontSize: 13, color: "#8892a4" }}>
        <span>{name}</span><span style={{ color }}>{level}%</span>
      </div>
      <div style={{ height: 6, background: "#1a2035", borderRadius: 99, overflow: "hidden" }}>
        <div style={{
          height: "100%", borderRadius: 99,
          background: `linear-gradient(90deg, ${color}, ${color}88)`,
          width: inView ? `${level}%` : "0%",
          transition: `width 1.2s cubic-bezier(0.4,0,0.2,1) ${delay}ms`,
          boxShadow: `0 0 10px ${color}60`,
        }} />
      </div>
    </div>
  );
}

/* ─── FLOATING CARD ─────────────────────────────────────────────────── */
function FloatCard({ children, delay = 0, style = {} }) {
  const [ref, inView] = useInView(0.1);
  return (
    <div ref={ref} style={{
      opacity: inView ? 1 : 0,
      transform: inView ? "translateY(0) scale(1)" : "translateY(40px) scale(0.96)",
      transition: `opacity 0.7s ease ${delay}ms, transform 0.7s cubic-bezier(0.34,1.56,0.64,1) ${delay}ms`,
      ...style,
    }}>
      {children}
    </div>
  );
}

/* ─── TILT CARD ─────────────────────────────────────────────────────── */
function TiltCard({ children, style = {}, className = "" }) {
  const cardRef = useRef(null);
  const onMove = useCallback(e => {
    const card = cardRef.current;
    if (!card) return;
    const rect = card.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    card.style.transform = `perspective(600px) rotateY(${x * 12}deg) rotateX(${-y * 12}deg) translateZ(8px)`;
    card.style.boxShadow = `${-x * 20}px ${y * 20}px 40px rgba(0,0,0,0.4), 0 0 30px rgba(0,229,255,0.08)`;
  }, []);
  const onLeave = useCallback(() => {
    const card = cardRef.current;
    if (!card) return;
    card.style.transform = "perspective(600px) rotateY(0deg) rotateX(0deg) translateZ(0)";
    card.style.boxShadow = "";
  }, []);
  return (
    <div ref={cardRef} className={className} onMouseMove={onMove} onMouseLeave={onLeave}
      style={{ transition: "transform 0.15s ease, box-shadow 0.15s ease", ...style }}>
      {children}
    </div>
  );
}

/* ─── MAGNETIC BUTTON ───────────────────────────────────────────────── */
function MagBtn({ children, onClick, className }) {
  const btnRef = useRef(null);
  const onMove = e => {
    const b = btnRef.current; if (!b) return;
    const r = b.getBoundingClientRect();
    const x = (e.clientX - r.left - r.width / 2) * 0.35;
    const y = (e.clientY - r.top - r.height / 2) * 0.35;
    b.style.transform = `translate(${x}px, ${y}px)`;
  };
  const onLeave = () => { if (btnRef.current) btnRef.current.style.transform = "translate(0,0)"; };
  return (
    <button ref={btnRef} className={className} onClick={onClick}
      onMouseMove={onMove} onMouseLeave={onLeave}
      style={{ transition: "transform 0.3s cubic-bezier(0.34,1.56,0.64,1)" }}>
      {children}
    </button>
  );
}

/* ─── CUSTOM CURSOR ─────────────────────────────────────────────────── */
function CustomCursor() {
  const dotRef = useRef(null);
  const ringRef = useRef(null);
  useEffect(() => {
    let mx = 0, my = 0, rx = 0, ry = 0;
    const onMove = e => { mx = e.clientX; my = e.clientY; };
    window.addEventListener("mousemove", onMove);
    let raf;
    const animate = () => {
      rx += (mx - rx) * 0.12; ry += (my - ry) * 0.12;
      if (dotRef.current) { dotRef.current.style.left = mx + "px"; dotRef.current.style.top = my + "px"; }
      if (ringRef.current) { ringRef.current.style.left = rx + "px"; ringRef.current.style.top = ry + "px"; }
      raf = requestAnimationFrame(animate);
    };
    animate();
    const onEnter = () => { if (ringRef.current) ringRef.current.style.transform = "translate(-50%,-50%) scale(1.8)"; };
    const onLeave = () => { if (ringRef.current) ringRef.current.style.transform = "translate(-50%,-50%) scale(1)"; };
    document.querySelectorAll("a,button,.tilt-card").forEach(el => {
      el.addEventListener("mouseenter", onEnter);
      el.addEventListener("mouseleave", onLeave);
    });
    return () => { cancelAnimationFrame(raf); window.removeEventListener("mousemove", onMove); };
  }, []);
  return (
    <>
      <div ref={dotRef} style={{ position:"fixed", width:8, height:8, borderRadius:"50%", background:"#00e5ff", pointerEvents:"none", zIndex:9999, transform:"translate(-50%,-50%)", transition:"transform 0.1s" }} />
      <div ref={ringRef} style={{ position:"fixed", width:36, height:36, borderRadius:"50%", border:"1.5px solid #00e5ff80", pointerEvents:"none", zIndex:9998, transform:"translate(-50%,-50%)", transition:"transform 0.4s cubic-bezier(0.34,1.56,0.64,1)" }} />
    </>
  );
}

/* ─── GLITCH TEXT ───────────────────────────────────────────────────── */
function GlitchText({ text, style = {} }) {
  return (
    <span style={{ position:"relative", display:"inline-block", ...style }} className="glitch" data-text={text}>
      {text}
    </span>
  );
}

/* ─── SCROLL PROGRESS ───────────────────────────────────────────────── */
function ScrollProgress() {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      const el = document.documentElement;
      setPct((el.scrollTop / (el.scrollHeight - el.clientHeight)) * 100);
    };
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);
  return (
    <div style={{ position:"fixed", top:0, left:0, right:0, height:3, zIndex:200, background:"#1a2035" }}>
      <div style={{ height:"100%", width:`${pct}%`, background:"linear-gradient(90deg,#00e5ff,#a78bfa)", transition:"width 0.1s", boxShadow:"0 0 10px #00e5ff" }} />
    </div>
  );
}

/* ─── SECTION WRAPPER ───────────────────────────────────────────────── */
function Section({ id, children, dark = false }) {
  const [ref, inView] = useInView(0.05);
  return (
    <section id={id} ref={ref} style={{
      padding:"110px 40px",
      background: dark ? "#0a0f1a" : "#060b14",
      position:"relative",
      opacity: inView ? 1 : 0,
      transform: inView ? "translateY(0)" : "translateY(30px)",
      transition:"opacity 0.8s ease, transform 0.8s ease",
    }}>
      {children}
    </section>
  );
}

/* ─── MAIN COMPONENT ────────────────────────────────────────────────── */
const NAV = ["About","Skills","Experience","Projects","Contact"];

export default function Portfolio() {
  const [active, setActive] = useState("About");
  const [menuOpen, setMenuOpen] = useState(false);
  const [hoverCard, setHoverCard] = useState(null);
  const typedRole = useTypingEffect(["PHP Full Stack Developer","Project Manager","ERP Architect","International Tech Lead","MERN Stack Developer"]);

  const scrollTo = id => { setMenuOpen(false); document.getElementById(id)?.scrollIntoView({ behavior:"smooth" }); };

  useEffect(() => {
    const obs = new IntersectionObserver(entries => entries.forEach(e => { if (e.isIntersecting) setActive(e.target.id); }), { threshold: 0.3 });
    NAV.forEach(n => { const el = document.getElementById(n); if (el) obs.observe(el); });
    return () => obs.disconnect();
