      <ParticleCanvas />
      <ScrollProgress />

      {/* ── NAV ── */}
      <nav style={{ position:"fixed", top:3, left:0, right:0, zIndex:100, display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 48px", background:"rgba(6,11,20,0.85)", backdropFilter:"blur(20px)", borderBottom:"1px solid #1a2035" }}>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <div style={{ width:40, height:40, borderRadius:12, background:"linear-gradient(135deg,#00e5ff,#0072ff)", display:"flex", alignItems:"center", justifyContent:"center", fontWeight:800, fontSize:18, color:"#000", boxShadow:"0 0 20px #00e5ff40" }}>R</div>
          <span style={{ fontWeight:800, fontSize:17, letterSpacing:"-0.3px" }}>Ram<span style={{ color:"#00e5ff" }}>.dev</span></span>
        </div>
